</span><span>, </span><span class="ͼe">grade</span><span>, </span><span class="ͼe">age</span><span>)</span><br><br><span class="ͼ6"># 4. Fit logistic regression</span><br><span class="ͼe">logit_fit</span><span> </span><span class="ͼ8">&lt;-</span><span> </span><span class="ͼe">glm</span><span>(</span><br><span>  </span><span class="ͼe">node_positive</span><span> </span><span class="ͼ8">~</span><span> </span><span class="ͼe">tumor_size</span><span> </span><span class="ͼ8">+</span><span> </span><span class="ͼe">grade</span><span> </span><span class="ͼ8">+</span><span> </span><span class="ͼe">age</span><span> </span><span class="ͼ8">+</span><span> </span><span class="ͼe">receptor_status</span><span>,</span><br><span>  </span><span class="ͼe">data</span><span> </span><span class="ͼ8">=</span><span> </span><span class="ͼe">df</span><span>,</span><br><span>  </span><span class="ͼe">family</span><span> </span><span class="ͼ8">=</span><span> </span><span class="ͼe">binomial</span><br><span>)</span><br><br><span class="ͼe">summary</span><span>(</span><span class="ͼe">logit_fit</span><span>)</span><br><br><span class="ͼ6"># 5. Odds ratios</span><br><span class="ͼe">exp</span><span>(</span><span class="ͼe">cbind</span><span>(</span><span class="ͼe">OR</span><span> </span><span class="ͼ8">=</span><span> </span><span class="ͼe">coef</span><span>(</span><span class="ͼe">logit_fit</span><span>), </span><span class="ͼe">confint</span><span>(</span><span class="ͼe">logit_fit</span><span>)))</span><br><br><span class="ͼ6"># 6. Predicted probabilities</span><br><span class="ͼe">df</span><span class="ͼ8">$</span><span class="ͼe">pred_prob</span><span> </span><span class="ͼ8">&lt;-</span><span> </span><span class="ͼe">predict</span><span>(</span><span class="ͼe">logit_fit</span><span>, </span><span class="ͼe">type</span><span> </span><span class="ͼ8">=</span><span> </span><span class="ͼc">"response"</span><span>)</span><br><br><span class="ͼ6"># 7. ROC curve</span><br><span class="ͼe">r