div id="code-block-viewer" dir="ltr" class="q9tKkq_viewer cm-editor z-10 light:cm-light dark:cm-light flex h-full w-full flex-col items-stretch ͼ5 ͼj"><div class="cm-scroller"><div class="cm-content q9tKkq_readonly"><span>01-oncology-survival-stage-analysis/</span><br><span>│</span><br><span>├── data/</span><br><span>│   └── lung_cancer_survival.csv</span><br><span>├── scripts/</span><br><span>│   └── survival_analysis.R</span><br><span>├── output/</span><br><span>│   ├── figures/</span><br><span>│   └── tables/</span><br><span>├── README.md</span><br><span>└── project_summary.md</span></div></div></div></div></div></div></div></div></div><div class=""><div class="" style="width: 100%; transform: none;"></div></div></div></div></div></pre>
